# Get the repo owner/name parts
$owner = "edburns"
$repoName = "Build26-BRK206-your-agent-anywhere-multiclient-multidevice-with-github-copilot-sdk"

# Get thread IDs for both comments
$result = gh api graphql -F number=55 -f query='
query($number: Int!) {
  repository(owner: "edburns", name: "Build26-BRK206-your-agent-anywhere-multiclient-multidevice-with-github-copilot-sdk") {
    pullRequest(number: $number) {
      reviewThreads(first: 100) {
        nodes {
          id
          isResolved
          comments(first: 1) { nodes { databaseId } }
        }
      }
    }
  }
}'

$result

# Get the repo owner/name parts
$owner = "edburns"
$repoName = "Build26-BRK206-your-agent-anywhere-multiclient-multidevice-with-github-copilot-sdk"

# Get thread IDs for both comments
$result = gh api graphql -F number=55 -f query='
query($number: Int!) {
  repository(owner: "edburns", name: "Build26-BRK206-your-agent-anywhere-multiclient-multidevice-with-github-copilot-sdk") {
    pullRequest(number: $number) {
      reviewThreads(first: 100) {
        nodes {
          id
          isResolved
          comments(first: 1) { nodes { databaseId } }
        }
      }
    }
  }
}'

$result

$REPO = "edburns/Build26-BRK206-your-agent-anywhere-multiclient-multidevice-with-github-copilot-sdk"
$PR = 55
$TIMEOUT = 600
$INTERVAL = 30
$ELAPSED = 0
# Track previous review IDs to detect new ones
$knownReviewId = 4739134578

while ($ELAPSED -lt $TIMEOUT) {
    # Strategy A: "Copilot's findings" - new review
    $reviews = gh api "/repos/$REPO/pulls/$PR/reviews" --jq '.[] | select(.body | test("Copilot.s findings|Pull request overview")) | select(.user.login | test("copilot-pull-request-reviewer")) | {id: .id, body: .body}' 2>$null

    $newReview = $null
    foreach ($line in ($reviews -split "`n")) {
        if ($line -match '"id":(\d+)') {
            $rid = [long]$Matches[1]
            if ($rid -ne $knownReviewId) {
                $newReview = $line
                break
            }
        }
    }

    if ($newReview) {
        Write-Output "NEW REVIEW FOUND after ${ELAPSED}s:"
        Write-Output $newReview

        # Check for new comments
        $newComments = gh api "/repos/$REPO/pulls/$PR/comments" --jq '.[] | select(.user.login | test("copilot-pull-request-reviewer|Copilot")) | select(.in_reply_to_id == null) | {id: .id, path: .path, line: .line, body: .body}' 2>$null

        # Filter out previously addressed comments (3617699607 and 3617699635)
        $unresolvedComments = @()
        foreach ($c in ($newComments -split "`n")) {
            if ($c -and $c -notmatch '"id":3617699607' -and $c -notmatch '"id":3617699635' -and $c.Trim().Length -gt 0) {
                $unresolvedComments += $c
            }
        }

        Write-Output "New unresolved comments: $($unresolvedComments.Count)"
        foreach ($c in $unresolvedComments) { Write-Output $c }
        break
    }

    Write-Output "No new review after ${ELAPSED}s, waiting..."
    Start-Sleep -Seconds $INTERVAL
    $ELAPSED += $INTERVAL
}

if (-not $newReview) {
    Write-Output "TIMEOUT: No new Copilot review found after ${TIMEOUT}s"
}

$REPO = "edburns/Build26-BRK206-your-agent-anywhere-multiclient-multidevice-with-github-copilot-sdk"
$PR = 55
$TIMEOUT = 600
$INTERVAL = 30
$ELAPSED = 0
# Track previous review IDs to detect new ones
$knownReviewId = 4739134578

while ($ELAPSED -lt $TIMEOUT) {
    # Strategy A: "Copilot's findings" - new review
    $reviews = gh api "/repos/$REPO/pulls/$PR/reviews" --jq '.[] | select(.body | test("Copilot.s findings|Pull request overview")) | select(.user.login | test("copilot-pull-request-reviewer")) | {id: .id, body: .body}' 2>$null

    $newReview = $null
    foreach ($line in ($reviews -split "`n")) {
        if ($line -match '"id":(\d+)') {
            $rid = [long]$Matches[1]
            if ($rid -ne $knownReviewId) {
                $newReview = $line
                break
            }
        }
    }

    if ($newReview) {
        Write-Output "NEW REVIEW FOUND after ${ELAPSED}s:"
        Write-Output $newReview

        # Check for new comments
        $newComments = gh api "/repos/$REPO/pulls/$PR/comments" --jq '.[] | select(.user.login | test("copilot-pull-request-reviewer|Copilot")) | select(.in_reply_to_id == null) | {id: .id, path: .path, line: .line, body: .body}' 2>$null

        # Filter out previously addressed comments (3617699607 and 3617699635)
        $unresolvedComments = @()
        foreach ($c in ($newComments -split "`n")) {
            if ($c -and $c -notmatch '"id":3617699607' -and $c -notmatch '"id":3617699635' -and $c.Trim().Length -gt 0) {
                $unresolvedComments += $c
            }
        }

        Write-Output "New unresolved comments: $($unresolvedComments.Count)"
        foreach ($c in $unresolvedComments) { Write-Output $c }
        break
    }

    Write-Output "No new review after ${ELAPSED}s, waiting..."
    Start-Sleep -Seconds $INTERVAL
    $ELAPSED += $INTERVAL
}

if (-not $newReview) {
    Write-Output "TIMEOUT: No new Copilot review found after ${TIMEOUT}s"
}

