$REPO = "edburns/Build26-BRK206-your-agent-anywhere-multiclient-multidevice-with-github-copilot-sdk"
$PR = 55
$TIMEOUT = 600
$INTERVAL = 30
$ELAPSED = 0
$knownReviewIds = @(4739134578, 4739165384)

while ($ELAPSED -lt $TIMEOUT) {
    $allReviews = gh api "/repos/$REPO/pulls/$PR/reviews" --jq '.[] | select(.user.login | test("copilot-pull-request-reviewer")) | .id' 2>$null

    $newFound = $false
    foreach ($rid in ($allReviews -split "`n")) {
        if ($rid -and $rid.Trim() -ne "" -and [long]$rid.Trim() -notin $knownReviewIds) {
            $newFound = $true
            $newId = $rid.Trim()
            break
        }
    }

    if ($newFound) {
        $body = gh api "/repos/$REPO/pulls/$PR/reviews/$newId" --jq '.body' 2>$null
        Write-Output "NEW REVIEW (id: $newId) after ${ELAPSED}s:"
        Write-Output $body
        break
    }

    Write-Output "No new review after ${ELAPSED}s..."
    Start-Sleep -Seconds $INTERVAL
    $ELAPSED += $INTERVAL
}

if (-not $newFound) {
    Write-Output "TIMEOUT: No new review after ${TIMEOUT}s"
}

